#!/usr/bin/env python3
# This file was generated by Cursor AI on 2026-05-04.
"""
Report benchmark filenames and run types where selected metrics increased vs control.

Metrics checked:
  - scq
  - num-tl-temporal-instructions
  - num-tl-instructions
  - sabre-total-bytes

Usage:
    python3 report_metric_increases_vs_control.py [RESULTS_DIR]

Default RESULTS_DIR is this script's directory joined with "results".
"""

from __future__ import annotations

import json
import sys
import textwrap
from pathlib import Path
from typing import Any

from virtual_best import SOURCE_RESULT_JSON, VIRTUAL_BEST_BASENAME, write_virtual_best

MAX_TABLE_WIDTH = 160
RESULT_JSON_FILES = SOURCE_RESULT_JSON + (VIRTUAL_BEST_BASENAME,)
INCREASE_KEYS = (
    "scq",
    "num-tl-temporal-instructions",
    "num-tl-instructions",
    "sabre-total-bytes",
)


def is_numeric(x: Any) -> bool:
    return isinstance(x, (int, float)) and not isinstance(x, bool)


def extract_stats_blob(entry: dict[str, Any]) -> dict[str, Any]:
    blobs = [v for k, v in entry.items() if k != "filename" and isinstance(v, dict)]
    if not blobs:
        return {}
    if len(blobs) == 1:
        return blobs[0]
    merged: dict[str, Any] = {}
    for blob in blobs:
        merged.update(blob)
    return merged


def load_by_filename(path: Path) -> dict[str, dict[str, Any]]:
    data = json.loads(path.read_text(encoding="utf-8"))
    out: dict[str, dict[str, Any]] = {}
    for entry in data.get("results", []):
        fn = entry.get("filename")
        if not fn:
            continue
        stats = extract_stats_blob(entry)
        if stats:
            out[str(fn)] = stats
    return out


def fmt_num(x: float, width: int = 14) -> str:
    if abs(x) >= 1e6 or (abs(x) < 1e-4 and x != 0.0):
        return f"{x:>{width}.6e}"
    return f"{x:>{width}.6f}".rstrip("0").rstrip(".").rjust(width)


def _table_row_width(col_widths: list[int]) -> int:
    return 1 + sum(w + 3 for w in col_widths)


def _compute_column_widths(
    headers: list[str],
    rows: list[list[str]],
    max_width: int,
    min_col: int = 3,
) -> list[int]:
    n = len(headers)
    inner_budget = max_width - 1 - 3 * n
    if inner_budget < n:
        min_col = max(1, inner_budget // max(n, 1))

    raw: list[int] = []
    for j in range(n):
        m = len(headers[j])
        for row in rows:
            if j < len(row):
                m = max(m, len(str(row[j])))
        raw.append(max(m, min_col))

    total_raw = sum(raw)
    if total_raw <= inner_budget:
        widths = raw
    else:
        widths = [max(min_col, int(r * inner_budget / total_raw)) for r in raw]
        diff = inner_budget - sum(widths)
        while diff > 0:
            idx = max(range(n), key=lambda i: raw[i] - widths[i])
            widths[idx] += 1
            diff -= 1
        while diff < 0:
            idx = max(range(n), key=lambda i: widths[i])
            if widths[idx] > min_col:
                widths[idx] -= 1
                diff += 1
            else:
                break
    return widths


def _wrap_cell(text: str, width: int) -> list[str]:
    lines = textwrap.wrap(
        text,
        width=width,
        break_long_words=True,
        break_on_hyphens=False,
    )
    return lines if lines else [""]


def _format_wrapped_physical_lines(
    cell_lines: list[list[str]],
    col_widths: list[int],
) -> list[str]:
    max_h = max((len(cl) for cl in cell_lines), default=1)
    out: list[str] = []
    for li in range(max_h):
        buf = "|"
        for j, w in enumerate(col_widths):
            chunk = cell_lines[j][li] if li < len(cell_lines[j]) else ""
            buf += f" {chunk:<{w}} |"
        out.append(buf)
    return out


def print_table(
    headers: list[str],
    rows: list[list[str]],
    title: str,
    max_width: int = MAX_TABLE_WIDTH,
) -> None:
    print()
    for title_line in textwrap.wrap(title, width=max_width, break_long_words=True) or [""]:
        print(title_line)

    str_rows: list[list[str]] = [[str(c) for c in row] for row in rows]
    col_widths = _compute_column_widths(headers, str_rows, max_width)
    while _table_row_width(col_widths) > max_width and max(col_widths) > 1:
        i = max(range(len(col_widths)), key=lambda k: col_widths[k])
        col_widths[i] -= 1

    def sep_line(char: str = "-") -> str:
        return "".join(["+" + char * (w + 2) for w in col_widths]) + "+"

    print(sep_line("="))
    hdr_cells = [_wrap_cell(headers[j], col_widths[j]) for j in range(len(headers))]
    for phys in _format_wrapped_physical_lines(hdr_cells, col_widths):
        print(phys)
    print(sep_line())
    for row in str_rows:
        padded = row + [""] * (len(headers) - len(row))
        cell_wrapped = [_wrap_cell(padded[j], col_widths[j]) for j in range(len(headers))]
        for phys in _format_wrapped_physical_lines(cell_wrapped, col_widths):
            print(phys)
    print(sep_line())


def main() -> int:
    script_dir = Path(__file__).resolve().parent
    results_dir = Path(sys.argv[1]) if len(sys.argv) > 1 else script_dir.parent / "results"
    results_dir = results_dir.resolve()

    if not results_dir.is_dir():
        print(f"Not a directory: {results_dir}", file=sys.stderr)
        return 1

    control_path = results_dir / "control.json"
    if not control_path.is_file():
        print(f"Missing {control_path}", file=sys.stderr)
        return 1

    vb_out = write_virtual_best(results_dir)
    if vb_out is None:
        print(
            f"Warning: {VIRTUAL_BEST_BASENAME} not regenerated (see virtual_best messages); "
            "using existing file if present.",
            file=sys.stderr,
        )

    control_map = load_by_filename(control_path)
    increase_rows_by_metric: dict[str, list[list[str]]] = {
        metric: [] for metric in INCREASE_KEYS
    }

    for basename in RESULT_JSON_FILES:
        if basename == "control.json":
            continue
        path = results_dir / basename
        if not path.is_file():
            print(f"Warning: missing results file, skipping compare: {path}", file=sys.stderr)
            continue
        run_type = path.stem
        var_map = load_by_filename(path)

        for benchmark_filename, control_stats in control_map.items():
            if benchmark_filename not in var_map:
                continue
            var_stats = var_map[benchmark_filename]
            for metric in INCREASE_KEYS:
                cval = control_stats.get(metric)
                vval = var_stats.get(metric)
                if not is_numeric(cval) or not is_numeric(vval):
                    continue
                assert isinstance(cval, (int, float))
                assert isinstance(vval, (int, float))
                cf = float(cval)
                vf = float(vval)
                if vf <= cf:
                    continue
                delta = vf - cf
                increase_rows_by_metric[metric].append(
                    [
                        benchmark_filename,
                        run_type,
                        fmt_num(cf),
                        fmt_num(vf),
                        fmt_num(delta),
                    ]
                )

    any_increase = False
    for metric in INCREASE_KEYS:
        rows = increase_rows_by_metric[metric]
        if rows:
            any_increase = True
            rows.sort(key=lambda r: (r[1], r[0]))
            print_table(
                ["benchmark filename", "run type", "control", "variant", "increase"],
                rows,
                f"Increases for metric '{metric}' vs control.json — {results_dir}",
            )
        else:
            print()
            print(f"No increases found for metric '{metric}' vs control.json.")

    if not any_increase:
        print()
        print("No increases found vs control.json for any selected metric.")

    return 0


if __name__ == "__main__":
    raise SystemExit(main())
